#!/usr/bin/env python3
import json
import re
import sys
from pathlib import Path


def clean_cell(cell: str) -> str:
    return re.sub(r"[*`]", "", cell).strip()


def parse_float(cell: str) -> float:
    match = re.search(r"-?\d+(?:\.\d+)?", clean_cell(cell))
    if not match:
        raise ValueError(f"No numeric value found in cell: {cell!r}")
    return float(match.group(0))


def extract_badge_rows(text: str) -> list[dict]:
    section = re.search(r"### Discrepancy by Nurse(.*?)(?:\n### |\Z)", text, flags=re.S)
    if not section:
        raise ValueError("Could not find Discrepancy by Nurse table")

    rows = []
    for line in section.group(1).splitlines():
        line = line.strip()
        if not line.startswith("|"):
            continue
        cells = [clean_cell(c) for c in line.strip("|").split("|")]
        if len(cells) != 6:
            continue
        if cells[0] == "ID" or set(cells[0]) <= {"-", ":"}:
            continue
        if not re.match(r"RN-\d+", cells[0]):
            continue
        rows.append(
            {
                "id": cells[0],
                "name": cells[1],
                "badge_hours": parse_float(cells[2]),
                "carescheduler_hours": parse_float(cells[3]),
                "discrepancy": parse_float(cells[4]),
            }
        )

    if not rows:
        raise ValueError("No nurse rows found in badge table")
    return rows


def main() -> None:
    if len(sys.argv) != 2:
        raise SystemExit("Usage: compute_badge_stats.py /path/to/workspace")

    root = Path(sys.argv[1])
    text = (root / "badge_access_analysis.md").read_text(encoding="utf-8")
    rows = extract_badge_rows(text)
    amy = next((row for row in rows if row["name"] == "Amy Chen"), None)
    if amy is None:
        raise ValueError("Amy Chen row not found")

    result = {
        "nurses_above_48h_badge": sum(1 for row in rows if row["badge_hours"] > 48.0),
        "nurses_above_60h_badge": sum(1 for row in rows if row["badge_hours"] > 60.0),
        "amy_chen_badge_hours": amy["badge_hours"],
        "avg_badge_hours": round(sum(row["badge_hours"] for row in rows) / len(rows), 1),
    }
    print(json.dumps(result, separators=(",", ":")))


if __name__ == "__main__":
    main()

